#include<bits/stdc++.h>
using namespace std;
int n,a[1000010],b[1000010],k;
__int128 s[1000010];
int lowbit(int x)
{
    return x&-x;
}
void add(int x,__int128 v)
{
    for(int i=x;i<=k;i+=lowbit(i))
    {
        s[i]+=v;
    }
}
__int128 query(int x)
{
    __int128 ans=0;
    for(int i=x;i>=1;i-=lowbit(i))
    {
        ans+=s[i];
    }
    return ans;
}
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        b[i]=a[i];
    }
    sort(b+1,b+1+n);
    k=unique(b+1,b+1+n)-b-1;
    __int128 ans=0;
    for(int i=1;i<=n;i++)
    {
        a[i]=lower_bound(b+1,b+1+k,a[i])-b;
        ans+=(query(k)-query(a[i]))*(n-i+1);
        add(a[i],i);
    }
    if(ans<1e18)
    {
        printf("%lld",(long long)(ans));
    }
    else
    {
        printf("%lld%018lld",(long long)(ans/(__int128)(1e18)),(long long)(ans%(__int128)(1e18)));
    }
    return 0;
}
